// Normalisiert + bereinigt das eingehende Long-Form-Asset.
// Erwartet ein Item aus der Quelle (CMS/RSS/Webhook). Feldnamen ggf. anpassen!
const src = $input.first().json;
const cfg = $('Set: Brand-Konfiguration').first().json;

// Quelle kann {items:[...]} ODER direkt das Asset liefern — beides abfangen.
const asset = Array.isArray(src.items) ? src.items[0]
  : Array.isArray(src) ? src[0]
  : (src.data && Array.isArray(src.data) ? src.data[0] : src);

if (!asset) {
  throw new Error('Kein Long-Form-Asset in der Antwort gefunden. Prüfe sourceApiUrl + Feld-Mapping.');
}

// === INDIVIDUELL: Feld-Mapping an deine Quelle anpassen ===
const title = asset.title || asset.name || asset.headline || '';
const rawBody = asset.body || asset.content || asset.description || asset.text || '';
const url = asset.url || asset.link || asset.permalink || '';
const contentType = asset.contentType || asset.type || 'blog';

// HTML-Tags grob entfernen + Whitespace normalisieren
const plain = String(rawBody)
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ')
  .trim();

if (!title || plain.length < 200) {
  throw new Error(`Asset zu kurz oder Titel fehlt (title='${title}', bodyLen=${plain.length}). Mindestens 200 Zeichen Body nötig.`);
}

// Auf ~6000 Zeichen kürzen (Token-Budget + Kosten-Schutz)
const clipped = plain.length > 6000 ? plain.slice(0, 6000) + ' …' : plain;

return [{
  json: {
    assetTitle: title,
    assetBody: clipped,
    assetUrl: url,
    assetContentType: contentType,
    assetHash: require('crypto').createHash('sha1').update(title + url).digest('hex').slice(0, 12),
    brandName: cfg.brandName,
    brandVoice: cfg.brandVoice,
    targetAudience: cfg.targetAudience,
    ctaDefault: cfg.ctaDefault,
    platforms: cfg.platforms,
    draftStoreUrl: cfg.draftStoreUrl,
    approvalEmail: cfg.approvalEmail,
    senderEmail: cfg.senderEmail
  }
}];

