// Parst die LLM-JSON-Antwort, validiert, splittet jeden Post in ein eigenes Item.
const resp = $input.first().json;
const ctx = $('Code: Asset bereinigen & normalisieren').first().json;

let content = '';
try {
  content = resp.choices[0].message.content;
} catch (e) {
  throw new Error('Unerwartete OpenRouter-Antwortstruktur: ' + JSON.stringify(resp).slice(0, 300));
}

// Defensive: evtl. doch Code-Fences entfernen
content = String(content).replace(/^```(json)?/i, '').replace(/```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('LLM-Output war kein valides JSON. Roh: ' + content.slice(0, 300));
}

const posts = Array.isArray(parsed.posts) ? parsed.posts : [];
if (posts.length < 5) {
  throw new Error(`Erwartet >=5 Posts, erhalten ${posts.length}. Prompt/Modell prüfen.`);
}

// Plattform-Längen-Limits zur Validierung
const LIMITS = { linkedin: 3000, twitter: 280, instagram: 2200 };

const items = posts.map((p, i) => {
  const platform = (p.platform || 'unknown').toLowerCase();
  const body = p.format === 'carousel'
    ? (Array.isArray(p.slides) ? p.slides.map((s, n) => `${n + 1}. ${s}`).join('\n') : '')
    : (p.body || '');
  const limit = LIMITS[platform] || 99999;
  const overLimit = body.length > limit;
  return {
    json: {
      idx: i + 1,
      platform,
      format: p.format || 'text',
      body,
      hashtags: Array.isArray(p.hashtags) ? p.hashtags : [],
      charCount: body.length,
      overLimit,
      status: overLimit ? 'needs_review' : 'draft',
      assetTitle: ctx.assetTitle,
      assetUrl: ctx.assetUrl,
      assetHash: ctx.assetHash,
      brandName: ctx.brandName,
      draftStoreUrl: ctx.draftStoreUrl,
      approvalEmail: ctx.approvalEmail,
      senderEmail: ctx.senderEmail,
      createdAt: new Date().toISOString()
    }
  };
});

return items;

// Baut den HTML-Freigabe-Digest aus allen Posts.
const rows = $input.first().json.data || [];
if (!rows.length) {
  return [{ json: { skip: true } }];
}
const first = rows[0];
const title = first.assetTitle || 'Asset';
const url = first.assetUrl || '';
const approvalEmail = first.approvalEmail;
const senderEmail = first.senderEmail;
const brandName = first.brandName || '';

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const cards = rows.map(r => {
  const flag = r.overLimit ? '<span style="color:#b91c1c;font-weight:600;">⚠ über Limit</span>' : '<span style="color:#15803d;">✓ ok</span>';
  return `<div style="border:1px solid #e5e7eb;border-radius:8px;padding:14px;margin:10px 0;">
    <div style="font-size:12px;color:#6b7280;text-transform:uppercase;letter-spacing:.04em;">${esc(r.platform)} · ${esc(r.format)} · ${r.charCount} Zeichen · ${flag}</div>
    <pre style="white-space:pre-wrap;font-family:inherit;font-size:14px;color:#111827;margin:8px 0 0;">${esc(r.body)}</pre>
    ${(r.hashtags && r.hashtags.length) ? `<div style="color:#2563eb;font-size:13px;margin-top:6px;">${esc(r.hashtags.join(' '))}</div>` : ''}
  </div>`;
}).join('');

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:640px;margin:0 auto;color:#111827;">
<h2 style="margin-bottom:2px;">${esc(brandName)} — ${rows.length} Social-Posts zur Freigabe</h2>
<p style="color:#6b7280;margin-top:0;">Quelle: <a href="${esc(url)}">${esc(title)}</a></p>
${cards}
<hr style="border:none;border-top:1px solid #eee;margin:18px 0;">
<p style="font-size:12px;color:#9ca3af;">Automatisch generiert von AEVUM Social-Repurpose. Diese Posts sind Entwürfe — vor Veröffentlichung prüfen. KI-gestützt erstellt.</p>
</body></html>`;

return [{ json: { html, approvalEmail, senderEmail, postCount: rows.length, assetTitle: title } }];

// Sammelt Fehler aus den Error-Pfaden (HTTP-Fetch / LLM / Store) zu einer Alert-Nachricht.
const err = $input.first().json;
const stage = err._stage || 'unbekannt';
const msg = (err.error && (err.error.message || err.error)) || err.message || JSON.stringify(err).slice(0, 300);
return [{
  json: {
    alertSubject: `[Social-Repurpose] FEHLER in Stufe: ${stage}`,
    alertBody: `Der Social-Repurpose-Workflow ist fehlgeschlagen.\n\nStufe: ${stage}\nFehler: ${msg}\nZeit: ${new Date().toISOString()}\n\nKein Post wurde generiert. Bitte prüfen.`,
    senderEmail: '{{INDIVIDUELL: Absender-Mail für Fehler-Alerts, z.B. no-reply@deinefirma.de}}',
    alertEmail: '{{INDIVIDUELL: Mail-Adresse für Fehler-Alerts, z.B. ops@deinefirma.de}}'
  }
}];
